SELECT count(*) FROM char_name, cast_info, role_type, title, name, kind_type, movie_info, movie_keyword, info_type WHERE cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id;